#include <bits/stdc++.h>
using namespace std;

int minPathSum(vector<vector<int>>& mat) {

    int m = mat.size();
    int n = mat[0].size();

    vector<vector<int>> dp(m,vector<int>(n,0));

    dp[0][0] = mat[0][0];

    for(int i = 1;i < m; i++){
        dp[i][0] = dp[i - 1][0] + mat[i][0];
    }
    for(int j = 1; j < n; j++){
        dp[0][j] = dp[0][j-1] + mat[0][j];
    }
    for(int i = 1; i < m; i++){
       for(int j = 1; j < n; j++) {
         dp[i][j] = min(dp[i - 1][j], dp[i][j - 1]) + mat[i][j];
       }
    }

    return dp[m - 1][n - 1];
}


int main() {

  int n, m;
  cin >> n >> m;

  assert(1 <= n && n <= 100);
  assert(1 <= m && m <= 100);

  vector<vector<int> > mat(n, vector<int> (m));
  for(int i = 0; i < n; i++){
    for(int j = 0; j < m; j++){
        cin >> mat[i][j];
    }
  } 

  cout << minPathSum(mat);


  return 0;
}

