    for(int i = 1; i < m; i++) {
        dp[i][0] = dp[i - 1][0] + mat[i][0];
    }

    for(int j = 1; j < n; j++) {
        dp[0][j] = dp[0][j - 1] + mat[0][j];
    }

    for(int i = 1; i < m; i++) {
        for(int j = 1; j < n; j++) {
            dp[i][j] = min(dp[i - 1][j], dp[i][j - 1]) + mat[i][j];
        }
    }

    return dp[m - 1][n - 1];
